import psycopg2

def connect_db():
    return psycopg2.connect(
        host="localhost",
        database="mydatabase",
        user="myuser",
        password="mypassword"
    )

def search_users(**kwargs):
    conn = connect_db()
    cur = conn.cursor(cursor_factory=psycopg2.extras.DictCursor)
    
    select_query = "SELECT * FROM users WHERE"
    
    conditions = []
    params = {}
    
    for key, value in kwargs.items():
        if value:
            conditions.append(f"{key} = %s")
            params[key] = value
            
    if len(conditions) > 0:
        where_clause = " AND ".join(conditions)
        query = select_query + " " + where_clause
        cur.execute(query, params)
        
        users = cur.fetchall()
        conn.close()
        return users
        
    else:
        conn.close()
        return []